"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[7845],{57154(e,t,r){r.r(t),r.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>p,frontMatter:()=>i,metadata:()=>n,toc:()=>c});const n=JSON.parse('{"id":"reference/cli-reference/stave-export-sir","title":"stave export-sir","description":"Export the Stave Intermediate Representation as JSON","source":"@site/../stave-guide/reference/cli-reference/stave-export-sir.md","sourceDirName":"reference/cli-reference","slug":"/reference/cli-reference/stave-export-sir","permalink":"/docs/reference/cli-reference/stave-export-sir","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":26,"frontMatter":{"title":"stave export-sir","sidebar_label":"export-sir","sidebar_position":26,"description":"Export the Stave Intermediate Representation as JSON"},"sidebar":"docs","previous":{"title":"export-controls","permalink":"/docs/reference/cli-reference/stave-export-controls"},"next":{"title":"export","permalink":"/docs/reference/cli-reference/stave-export"}}');var o=r(74848),s=r(28453);const i={title:"stave export-sir",sidebar_label:"export-sir",sidebar_position:26,description:"Export the Stave Intermediate Representation as JSON"},a="stave export-sir",l={},c=[];function d(e){const t={code:"code",h1:"h1",header:"header",pre:"pre",...(0,s.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"stave-export-sir",children:"stave export-sir"})}),"\n",(0,o.jsx)(t.pre,{children:(0,o.jsx)(t.code,{className:"language-text",children:'Export the Stave Intermediate Representation (SIR) for the configured\ncontrols and observations as a deterministic document.\n\nThe SIR is the vendor-neutral fact set the Z3 solver consumes for compound\nrisk reasoning. It carries every control fact, asset, identity (with\ntransitive role chains), effective-permission edge, and exposure window\nthat the engine\'s evaluation pipeline produces \u2014 but stripped of\ninfrastructure noise (file paths, git metadata, tool versions).\n\nScope: the SIR is a curated projection, not a complete dump of every\nproperty a control reads. The export currently covers 13 top-level\nconfiguration domains (IAM, Cognito, S3 storage policies, Bedrock AI\nagents, delegation, credential lifecycle, trail logging, network, and\na subset of compute / k8s). Properties in uncovered domains (Azure,\nGCP, M365, databases, messaging, secrets, monitoring, and 80+ others)\nare evaluated by CEL controls inside \'stave apply\' but are NOT in the\nexport. A solver UNSAT verdict is valid for chains the SIR can express;\nit is silent about chains whose members live in uncovered domains. See\nthe Fact Export reference in stave-guide for the full domain table.\n\nThree output formats are supported:\n\n  json    \u2014 full nested SIR document (default).\n  jsonl   \u2014 one (subject, predicate, object) triple per line. Lossy\n            projection optimised for Datalog/Souffl\xe9 and ASP/Clingo\n            consumers that prefer flat predicate(s, o) facts.\n  smt2    \u2014 SMT-LIB v2 declarations + assertions. The output contains\n            facts only \u2014 no (check-sat), no queries \u2014 so any SMT solver\n            (Z3, cvc5, Yices) reads the same file. Reasoning programs\n            append their own query to the file before invoking the\n            solver.\n\nInputs:\n  --controls, -i      Control definitions directory (default: controls)\n  --observations, -o  Observation snapshots directory (default: observations)\n  --format, -f        Output format: json | jsonl | smt2 (default: json)\n  --now               RFC3339 timestamp for deterministic output\n\nOutputs:\n  stdout: SIR document in the requested format.\n  stderr: errors and progress (when stderr is a TTY).\n\nExit codes:\n  0   success\n  2   input error (bad flag, malformed --now)\n  4   internal error (load failure, builder error)\n  130 SIGINT\n\nUsage:\n  stave export-sir [flags]\n\nExamples:\n  # Export SIR for the project\'s default controls + observations\n  stave export-sir > sir.json\n\n  # Pin --now for byte-identical reproduction\n  stave export-sir --now 2026-05-01T12:00:00Z > sir.json\n\n  # Pretty-print for inspection\n  stave export-sir | jq .\n\n  # Triple form for Datalog / ASP consumers\n  stave export-sir --format jsonl > facts.jsonl\n\n  # SMT-LIB v2 facts; append a query before piping into z3 / cvc5\n  stave export-sir --format smt2 > facts.smt2\n  cat facts.smt2 query.smt2 | z3 -in\n\nFlags:\n      --allowlist-mode string   scalar projector mode: curated (default \u2014 59 hand-authored entries) | full (experimental \u2014 emit one auto_prop_<path> triple per control-read property path the predicate index advertises; measures coverage gain, no downstream solver consumes the auto_prop_* names yet) (default "curated")\n      --closed-world            emit closed-world forall axioms in SMT2 output (restricts each predicate to its asserted tuples only; needed for negative proofs but causes solver timeout on large fact sets)\n  -i, --controls string         control definitions directory (default "controls")\n  -f, --format string           output format: json | jsonl | smt2 (default "json")\n  -h, --help                    help for export-sir\n      --now string              override current time (RFC3339) for deterministic output\n  -o, --observations string     observation snapshots directory (default "observations")\n      --strip-catalog           omit control catalog metadata (has_severity, has_type, has_domain) from the fact stream; reduces SMT2/JSONL output to observation-derived facts only\n      --validate                check SIR coverage against CEL controls and warn on stderr about projection gaps (controls that fire in CEL but evaluate properties not projected as SIR facts)\n\nGlobal Flags:\n      --allow-symlink-output   Allow writing output through symlinks (default: refuse)\n      --force                  Allow overwriting existing output files\n      --log-file string        Write logs to file (default: stderr)\n      --log-format string      Log format: text|json (default "text")\n      --log-level string       Log level: debug|info|warn|error (overrides -v)\n      --log-timestamps         Include timestamps in logs (breaks determinism)\n      --log-timings            Include timing information (breaks determinism)\n      --no-color               Disable ANSI colors in output\n      --path-mode string       Path rendering in errors/logs: base (basename only) or full (absolute paths) Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --quiet                  Suppress output (exit code only) Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --require-offline        Assert offline operation: fail if proxy env vars (HTTP_PROXY, HTTPS_PROXY, ALL_PROXY) are set\n      --sanitize               Sanitize infrastructure identifiers (bucket names, ARNs, policies) from output Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --strict                 Enable strict integrity checks for embedded registries and references\n  -v, --verbose count          Increase verbosity (-v=INFO, -vv=DEBUG)\n  -y, --yes                    Auto-confirm all interactive prompts (distinct from --force which controls file overwriting)\n'})})]})}function p(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},28453(e,t,r){r.d(t,{R:()=>i,x:()=>a});var n=r(96540);const o={},s=n.createContext(o);function i(e){const t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:i(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);